head.script:
/*  */
(function(){
  console.log("SVG Bootloader: Waking up...");
  const XHTML_NS="http://www.w3.org/1999/xhtml";
  const root=document.querySelector("foreignObject").firstElementChild;
  const head=root.querySelector("head");
  const body=root.querySelector("body");
  const originalCreateElement=document.createElement.bind(document);
  const originalCreateElementNS=document.createElementNS.bind(document);

  Object.defineProperty(document,"head",{get(){return head},configurable:true});
  Object.defineProperty(document,"body",{get(){return body},configurable:true});
  Object.defineProperty(document,"documentElement",{get(){return root},configurable:true});

  document.createElement=function(t,o){
    return (typeof t==="string") ? originalCreateElementNS(XHTML_NS,t,o) : originalCreateElement(t,o);
  };

  if(!location.hash){history.replaceState(history.state,"","#/");}
  window.GH_BASE = "https://cdn.jsdelivr.net/gh/vibec3der/svg@main/";
  console.log("SVG Bootloader: Environment Patched.");
})();
/*  */
